select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = c.postid and p.id = pl.relatedpostid and p.id = v.postid and u.id = p.owneruserid and u.id = b.userid and c.score=2 and p.viewcount<=7710 and p.commentcount<=12 and p.favoritecount>=0 and p.favoritecount<=4 and p.creationdate>=timestamp '2010-07-27 03:58:22' and u.upvotes>=0;
